    25|const DEPLOYMENT_BRAIN_VERSION = 'ivx-deployment-brain-v2-2026-07-02T12:35:00Z';
    26|
    27|// Production URLs — RENDER_EXTERNAL_URL is set by Render at runtime.
    28|const PRODUCTION_BASE = process.env.RENDER_EXTERNAL_URL?.replace(/\/$/, '')
    29|  || 'https://ivx-holdings-platform.onrender.com';
    30|const API_BASE = PRODUCTION_BASE;
