    32|const CHAT_FRONTEND_URL = 'https://chat.ivxholding.com';
    33|const RENDER_SERVICE_ID = process.env.RENDER_SERVICE_ID?.trim() || 'srv-d7t9ivreo5us73ftose0';
    34|const GITHUB_REPO = process.env.GITHUB_REPO_URL?.trim()
