    91|
    92|async function fetchJson(url: string): Promise<{ ok: boolean; status: number; body: unknown }> {
    93|  try {
    94|    const res = await fetch(url, { signal: AbortSignal.timeout(15000) });
    95|    const text = await res.text();
    96|    let body: unknown = text;
    97|    try { body = JSON.parse(text); } catch {}
    98|    return { ok: res.ok, status: res.status, body };
    99|  } catch (err) {
   100|    return { ok: false, status: 0, body: { error: err instanceof Error ? err.message : 'Network error' } };
   101|  }
