   103|
   104|function extractSha(data: unknown): string | null {
   105|  if (data && typeof data === 'object') {
   106|    const d = data as Record<string, unknown>;
   107|    return (typeof d.commit === 'string' ? d.commit : null) ??
   108|           (typeof d.commitShort === 'string' ? d.commitShort : null) ??
   109|           null;
   110|  }
   111|  return null;
