   114|// ── GitHub & Render Helpers ──────────────────────────────────────────────
   115|
   116|/**
   117| * Fetch the GitHub commit SHA. Tries the GitHub API first with the token.
   118| * If the token is expired/invalid (401), falls back to the Render deploy API
   119| * which reports the commit SHA of the connected GitHub repo's latest deploy.
   120| */
   121|async function resolveGitHubSha(renderInfo?: RenderInfo): Promise<GitHubShaResult> {
   122|  const token = process.env.GITHUB_TOKEN?.trim();
   123|
   124|  if (token) {
   125|    try {
   126|      const res = await fetch(`https://api.github.com/repos/${GITHUB_REPO}/commits?per_page=1`, {
   127|        headers: { Authorization: `Bearer ${token}`, Accept: 'application/vnd.github+json' },
   128|        signal: AbortSignal.timeout(10000),
   129|      });
   130|      if (res.ok) {
   131|        const data = await res.json() as Array<{ sha: string }>;
   132|        if (data[0]?.sha) {
   133|          return { sha: data[0].sha, source: 'github_api', tokenStatus: 'VALID' };
   134|        }
   135|      }
   136|      if (res.status === 401) {
   137|        console.log('[DeploymentBrain] GitHub token returned 401 — falling back to Render deploy SHA');
   138|      } else {
   139|        console.log(`[DeploymentBrain] GitHub API returned HTTP ${res.status} — falling back to Render deploy SHA`);
   140|      }
   141|    } catch (err) {
   142|      console.log('[DeploymentBrain] GitHub API fetch failed — falling back to Render deploy SHA:', err instanceof Error ? err.message : 'unknown');
   143|    }
   144|  }
   145|
   146|  // Fallback: Render deploy API includes the commit SHA from the connected GitHub repo
   147|  const info = renderInfo ?? await fetchRenderInfo();
   148|  if (info.sha) {
   149|    return {
   150|      sha: info.sha,
   151|      source: 'render_deploy_commit',
   152|      tokenStatus: token ? 'EXPIRED_OR_INVALID' : 'NOT_SET',
   153|    };
   154|  }
   155|
   156|  return { sha: null, source: 'none', tokenStatus: token ? 'EXPIRED_OR_INVALID' : 'NOT_SET' };
   157|}
   158|
   159|async function fetchRenderInfo(): Promise<RenderInfo> {
   160|  const apiKey = process.env.RENDER_API_KEY?.trim();
   161|  const serviceId = RENDER_SERVICE_ID;
   162|
   163|  if (!apiKey) {
   164|    return { serviceId, deployId: null, sha: null, status: 'autoDeployTrigger: commit active', repo: null, error: null, deployHistory: [] };
   165|  }
   166|
   167|  try {
   168|    const [svcRes, deployRes] = await Promise.all([
   169|      fetch(`https://api.render.com/v1/services/${serviceId}`, {
   170|        headers: { Authorization: `Bearer ${apiKey}`, Accept: 'application/json' },
   171|        signal: AbortSignal.timeout(10000),
   172|      }),
   173|      fetch(`https://api.render.com/v1/services/${serviceId}/deploys?limit=5`, {
   174|        headers: { Authorization: `Bearer ${apiKey}`, Accept: 'application/json' },
   175|        signal: AbortSignal.timeout(10000),
   176|      }),
   177|    ]);
   178|
   179|    const svcData = svcRes.ok ? await svcRes.json() as Record<string, unknown> : null;
   180|    const deployData = deployRes.ok ? await deployRes.json() as Array<Record<string, unknown>> : null;
   181|    const latestDeploy = deployData?.[0] as Record<string, unknown> | undefined;
   182|
   183|    const history: Array<{ deployId: string; status: string; commitSha: string; createdAt: string }> =
   184|      (deployData ?? []).slice(0, 5).map((d) => {
   185|        const deploy = (d.deploy ?? d) as Record<string, unknown>;
   186|        const commit = deploy.commit as Record<string, unknown> | undefined;
   187|        return {
   188|          deployId: (deploy.id as string) ?? 'unknown',
   189|          status: (deploy.status as string) ?? 'unknown',
   190|          commitSha: (commit?.id as string) ?? 'unknown',
   191|          createdAt: (deploy.createdAt as string) ?? 'unknown',
   192|        };
   193|      });
   194|
   195|    return {
   196|      serviceId,
   197|      deployId: (latestDeploy?.id as string) ?? null,
   198|      sha: (latestDeploy?.commit as Record<string, unknown>)?.id as string ?? null,
   199|      status: (latestDeploy?.status as string) ?? 'unknown',
   200|      repo: (svcData?.repo as string) ?? null,
   201|      error: null,
   202|      deployHistory: history,
   203|    };
   204|  } catch (err) {
   205|    return { serviceId, deployId: null, sha: null, status: null, repo: null, error: err instanceof Error ? err.message : 'Render API unreachable', deployHistory: [] };
   206|  }
   207|}
