   209|async function fetchSupabaseTableCounts(): Promise<string> {
   210|  const url = process.env.SUPABASE_URL?.trim();
   211|  const key = process.env.SUPABASE_SERVICE_ROLE_KEY?.trim();
   212|  if (!url || !key) return 'SUPABASE_URL or SUPABASE_SERVICE_ROLE_KEY not configured in this environment.';
   213|
   214|  const tables = ['properties', 'members', 'investors', 'wallets', 'public_chat_messages', 'ai_usage_logs', 'ivx_agent_jobs'];
   215|  const results: string[] = [];
   216|
   217|  for (const table of tables) {
   218|    try {
   219|      const res = await fetch(`${url}/rest/v1/${table}?select=count`, {
   220|        headers: { apikey: key, Authorization: `Bearer ${key}`, Prefer: 'count=exact' },
   221|        signal: AbortSignal.timeout(8000),
   222|      });
   223|      const data = await res.json() as unknown[];
   224|      results.push(`${table}: ${Array.isArray(data) ? data.length : '?'} rows`);
   225|    } catch {
   226|      results.push(`${table}: ERROR`);
   227|    }
   228|  }
   229|  return results.join('\n');
   230|}
