   234|export async function handleDeployStatus(): Promise<string> {
   235|  const renderInfo = await fetchRenderInfo();
   236|  const [healthRes, versionRes, githubResult] = await Promise.all([
   237|    fetchJson(`${API_BASE}/health`),
   238|    fetchJson(`${API_BASE}/version`),
   239|    resolveGitHubSha(renderInfo),
   240|  ]);
   241|
   242|  const healthSha = extractSha(healthRes.body);
   243|  const versionSha = extractSha(versionRes.body);
   244|  const healthy = healthRes.status === 200;
   245|  const bootTime = healthRes.body && typeof healthRes.body === 'object'
   246|    ? (healthRes.body as Record<string, unknown>).bootTime ?? null
   247|    : null;
   248|
   249|  const githubSha = githubResult.sha;
   250|  const commitMatch = healthSha !== null && healthSha === versionSha && healthSha === githubSha && healthSha === renderInfo.sha;
   251|
   252|  const result: DeployStatusResult = {
   253|    github: {
   254|      sha: githubSha,
   255|      repo: renderInfo.repo || GITHUB_REPO,
   256|      branch: 'main',
   257|      error: githubSha ? null : `GITHUB_TOKEN ${githubResult.tokenStatus} — SHA sourced from ${githubResult.source}`,
   258|    },
   259|    render: {
   260|      serviceId: renderInfo.serviceId || RENDER_SERVICE_ID,
   261|      deployId: renderInfo.deployId,
   262|      sha: renderInfo.sha,
   263|      status: renderInfo.status,
   264|      error: renderInfo.error,
   265|    },
   266|    production: {
   267|      sha: healthSha,
   268|      bootTime: typeof bootTime === 'string' ? bootTime : null,
   269|      healthy,
   270|      error: null,
   271|    },
   272|    commitMatch,
   273|    timestamp: nowIso(),
   274|  };
   275|
   276|  return formatDeployStatus(result, { githubSource: githubResult.source, tokenStatus: githubResult.tokenStatus });
   277|}
   278|
   279|function formatDeployStatus(result: DeployStatusResult, meta?: { githubSource: string; tokenStatus: string }): string {
   280|  const lines = [
   281|    '## IVX Deployment Status',
   282|    '',
   283|    `**Timestamp:** ${result.timestamp}`,
   284|    '',
   285|    '### Production',
   286|    `- Health SHA: \`${result.production.sha ?? 'UNKNOWN'}\``,
   287|    `- Healthy: ${result.production.healthy ? 'YES' : 'NO'}`,
   288|    `- Boot Time: ${result.production.bootTime ?? 'UNKNOWN'}`,
   289|    '',
   290|    '### GitHub',
   291|    `- Repo: ${result.github.repo}`,
   292|    `- Branch: ${result.github.branch}`,
   293|    `- SHA: \`${result.github.sha ?? 'UNVERIFIED'}\``,
   294|    `- SHA Source: ${meta?.githubSource ?? 'unknown'}`,
   295|    `- Token Status: ${meta?.tokenStatus ?? 'unknown'}`,
   296|    result.github.error ? `- Note: ${result.github.error}` : '',
   297|    '',
   298|    '### Render',
   299|    `- Service: ${result.render.serviceId}`,
   300|    `- Deploy ID: ${result.render.deployId ?? 'UNVERIFIED'}`,
   301|    `- Deployed SHA: \`${result.render.sha ?? 'UNVERIFIED'}\``,
   302|    `- Status: ${result.render.status ?? 'UNVERIFIED'}`,
   303|    result.render.error ? `- Error: ${result.render.error}` : '',
   304|    '',
   305|    '### Commit Match',
   306|    `**${result.commitMatch ? 'MATCH — all SHAs align' : 'NO — SHAs diverge'}**`,
   307|    '',
   308|    '### Deploy Path',
   309|    '1. Code pushed to GitHub main',
   310|    '2. Render autoDeployTrigger: commit fires on new commits',
   311|    `3. Production ${API_BASE} gets new code`,
   312|    '',
   313|    `_Brain: ${DEPLOYMENT_BRAIN_VERSION}_`,
   314|  ];
   315|
   316|  return lines.filter(l => l !== null).join('\n');
   317|}
