   319|export async function handleCommitMatch(): Promise<string> {
   320|  const renderInfo = await fetchRenderInfo();
   321|  const [healthRes, versionRes, githubResult] = await Promise.all([
   322|    fetchJson(`${API_BASE}/health`),
   323|    fetchJson(`${API_BASE}/version`),
   324|    resolveGitHubSha(renderInfo),
   325|  ]);
   326|
   327|  const healthSha = extractSha(healthRes.body);
   328|  const versionSha = extractSha(versionRes.body);
   329|  const githubSha = githubResult.sha;
   330|  const renderSha = renderInfo.sha;
   331|  const match = healthSha === versionSha && healthSha !== null;
   332|  const fullMatch = match && healthSha === githubSha && healthSha === renderSha;
   333|
   334|  const lines = [
   335|    '## Commit Match Check',
   336|    '',
   337|    `**Health SHA:** \`${healthSha ?? 'UNKNOWN'}\``,
   338|    `**Version SHA:** \`${versionSha ?? 'UNKNOWN'}\``,
   339|    `**GitHub SHA:** \`${githubSha ?? 'UNVERIFIED'}\` (source: ${githubResult.source})`,
   340|    `**Render SHA:** \`${renderSha ?? 'UNVERIFIED'}\``,
   341|    `**Match:** ${fullMatch ? 'YES — all SHAs align' : match ? 'PARTIAL — Health/Version match' : 'NO — SHAs diverge'}`,
   342|    '',
   343|    `GitHub Token: ${githubResult.tokenStatus}`,
   344|    `Render Deploy ID: ${renderInfo.deployId ?? 'UNVERIFIED'}`,
   345|    `Render Status: ${renderInfo.status ?? 'UNVERIFIED'}`,
   346|    '',
   347|    match
   348|      ? 'Production endpoints agree on the running commit.'
   349|      : 'Production is running different code on /health vs /version. Deploy propagation may be in progress.',
   350|    '',
   351|    `_Brain: ${DEPLOYMENT_BRAIN_VERSION}_`,
   352|  ];
   353|  return lines.join('\n');
   354|}
