   356|export async function handleDeployEvidence(): Promise<string> {
   357|  const renderInfo = await fetchRenderInfo();
   358|  const [healthRes, versionRes, githubResult] = await Promise.all([
   359|    fetchJson(`${API_BASE}/health`),
   360|    fetchJson(`${API_BASE}/version`),
   361|    resolveGitHubSha(renderInfo),
   362|  ]);
   363|
   364|  const healthSha = extractSha(healthRes.body);
   365|  const versionSha = extractSha(versionRes.body);
   366|  const githubSha = githubResult.sha;
   367|  const renderDeployId = renderInfo.deployId;
   368|  const renderDeployedSha = renderInfo.sha;
   369|
   370|  const evidence: DeployEvidenceResult = {
   371|    githubSha,
   372|    renderDeployId,
   373|    renderDeployedSha,
   374|    healthSha,
   375|    versionSha,
   376|    commitMatch: healthSha === versionSha && healthSha === githubSha && healthSha === renderDeployedSha && healthSha !== null,
   377|    productionStatus: healthRes.status === 200 ? 'healthy' : 'degraded',
   378|    errors: [],
   379|    timestamp: nowIso(),
   380|  };
   381|
   382|  if (!healthSha) evidence.errors.push('Health SHA not found');
   383|  if (!versionSha) evidence.errors.push('Version SHA not found');
   384|  if (!githubSha) evidence.errors.push('GitHub SHA not found');
   385|  if (!renderDeployId) evidence.errors.push('Render Deploy ID not found');
   386|
   387|  const lines = [
   388|    '## IVX Deployment Evidence',
   389|    '',
   390|    `**Timestamp:** ${evidence.timestamp}`,
   391|    '',
   392|    '| Source | SHA |',
   393|    '|--------|-----|',
   394|    `| Health | \`${evidence.healthSha ?? 'UNKNOWN'}\` |`,
   395|    `| Version | \`${evidence.versionSha ?? 'UNKNOWN'}\` |`,
   396|    `| GitHub | \`${evidence.githubSha ?? 'UNVERIFIED'}\` (via ${githubResult.source}) |`,
   397|    `| Render | \`${evidence.renderDeployedSha ?? 'UNVERIFIED'}\` |`,
   398|    '',
   399|    `**Render Deploy ID:** \`${evidence.renderDeployId ?? 'UNVERIFIED'}\``,
   400|    `**Render Status:** ${renderInfo.status ?? 'UNVERIFIED'}`,
   401|    `**GitHub Token:** ${githubResult.tokenStatus}`,
   402|    `**Commit Match:** ${evidence.commitMatch ? 'YES — all SHAs align' : 'NO'}`,
   403|    `**Production:** ${evidence.productionStatus}`,
   404|    '',
   405|    evidence.errors.length > 0 ? `**Errors:** ${evidence.errors.join('; ')}` : '**No errors.**',
   406|    '',
   407|    '### Deploy History (last 5)',
   408|    ...(renderInfo.deployHistory.length > 0
   409|      ? renderInfo.deployHistory.map((d) => `- \`${d.deployId}\` ${d.status} @ \`${d.commitSha.slice(0, 8)}\` ${d.createdAt}`)
   410|      : ['- No deploy history available']),
   411|    '',
   412|    `_Brain: ${DEPLOYMENT_BRAIN_VERSION}_`,
   413|  ];
   414|  return lines.join('\n');
   415|}
