   481|export async function handleDeployRollback(): Promise<string> {
   482|  const apiKey = process.env.RENDER_API_KEY?.trim();
   483|  const serviceId = RENDER_SERVICE_ID;
   484|
   485|  if (!apiKey) {
   486|    return [
   487|      '## Deploy Rollback — BLOCKED',
   488|      '',
   489|      '**Reason:** RENDER_API_KEY is not available.',
   490|      '',
   491|      '**Manual rollback:**',
   492|      '1. Visit Render dashboard → select service → Deploys → select previous deploy → "Rollback to this deploy"',
   493|      '2. Or push a revert commit to main',
   494|      '',
   495|      `_Brain: ${DEPLOYMENT_BRAIN_VERSION}_`,
   496|    ].join('\n');
   497|  }
   498|
   499|  try {
   500|    const deploysRes = await fetch(`https://api.render.com/v1/services/${serviceId}/deploys?limit=5`, {
   501|      headers: { Authorization: `Bearer ${apiKey}`, Accept: 'application/json' },
   502|      signal: AbortSignal.timeout(10000),
   503|    });
   504|    if (!deploysRes.ok) {
   505|      return `## Deploy Rollback — FAILED\n\nCould not fetch deploy history (HTTP ${deploysRes.status}).\n\n_Brain: ${DEPLOYMENT_BRAIN_VERSION}_`;
   506|    }
   507|    const deploys = await deploysRes.json() as Array<Record<string, unknown>>;
   508|    const liveDeploys = deploys.filter((d) => {
   509|      const deploy = (d.deploy ?? d) as Record<string, unknown>;
   510|      return deploy.status === 'live';
   511|    });
