    82|// ─── Read a value (tries IVX_ prefix first, then fallback) ──────────
    83|
    84|function readEnv(name: string): string {
    85|  return (process.env[name] ?? '').trim();
    86|}
    87|
    88|function readVault(ivxName: string, fallbackName: string | null): {
    89|  present: boolean;
    90|  source: 'ivx' | 'fallback' | 'none';
    91|  sourceVar: string | null;
    92|  value: string;
    93|} {
    94|  const ivxValue = readEnv(ivxName);
    95|  if (ivxValue) {
    96|    return { present: true, source: 'ivx', sourceVar: ivxName, value: ivxValue };
    97|  }
    98|  if (fallbackName) {
    99|    const fallbackValue = readEnv(fallbackName);
   100|    if (fallbackValue) {
   101|      return { present: true, source: 'fallback', sourceVar: fallbackName, value: fallbackValue };
   102|    }
   103|  }
   104|  return { present: false, source: 'none', sourceVar: null, value: '' };
   105|}
