   334|/**
   335| * Run a full vault audit: inspect every variable, run live tests, and
   336| * produce a blocking/missing report. Never returns secret values.
   337| */
   338|export async function auditVault(): Promise<VaultAudit> {
   339|  const variables: VaultVariableStatus[] = [];
   340|  const blockers: string[] = [];
   341|  const requiredMissing: string[] = [];
   342|
   343|  // Inspect all vault variables in parallel (with a concurrency cap of 5)
   344|  const chunks: VaultEntry[][] = [];
   345|  for (let i = 0; i < VAULT_REGISTRY.length; i += 5) {
   346|    chunks.push(VAULT_REGISTRY.slice(i, i + 5));
   347|  }
   348|
   349|  for (const chunk of chunks) {
   350|    const results = await Promise.all(
   351|      chunk.map((entry) => inspectVaultVariable(entry.ivxName)),
   352|    );
   353|    for (const result of results) {
   354|      if (result) variables.push(result);
   355|    }
   356|  }
   357|
   358|  for (const v of variables) {
   359|    if (!v.present) {
   360|      if (v.required) {
   361|        requiredMissing.push(v.name);
   362|        blockers.push(`MISSING_REQUIRED: ${v.name} — ${v.purpose}. Set ${v.name} in Render env vars or .env.`);
   363|      }
   364|    } else if (v.tested && v.testOk === false) {
   365|      blockers.push(`INVALID: ${v.name} — test failed: ${v.testDetail}. Source: ${v.sourceVar}.`);
   366|    }
   367|  }
   368|
   369|  const present = variables.filter((v) => v.present).length;
   370|  const missing = variables.filter((v) => !v.present).length;
   371|  const tested = variables.filter((v) => v.tested).length;
   372|  const passed = variables.filter((v) => v.tested && v.testOk === true).length;
   373|  const failed = variables.filter((v) => v.tested && v.testOk === false).length;
