   378|    total: variables.length,
   379|    present,
   380|    missing,
   381|    tested,
   382|    passed,
   383|    failed,
   384|    variables,
   385|    requiredPresent: requiredMissing.length === 0,
   386|    requiredMissing,
   387|    blockers,
   388|    secretValuesReturned: false,
   389|  };
