# Get handoff readiness and tool system details
TOKEN="dev-open-access-token"
BASE="https://ivx-holdings-platform.onrender.com"

echo "=== HANDOFF READINESS ==="
curl -s "$BASE/api/ivx/handoff/readiness" -H "Authorization: Bearer $TOKEN" 2>/dev/null | python3 -c "
import sys, json
d = json.load(sys.stdin)
if isinstance(d, dict):
    for k in sorted(d.keys())[:20]:
        v = d[k]
        if isinstance(v, (str, int, float, bool)):
            print(f'  {k}: {v}')
        elif isinstance(v, dict):
            print(f'  {k}: {json.dumps(v)[:100]}')
        elif isinstance(v, list):
            print(f'  {k}: [{len(v)} items]')
" 2>/dev/null

echo ""
echo "=== TOOL SYSTEM DASHBOARD ==="
curl -s "$BASE/api/ivx/tool-system/dashboard" -H "Authorization: Bearer $TOKEN" 2>/dev/null | python3 -c "
import sys, json
d = json.load(sys.stdin)
if isinstance(d, dict):
    for k in sorted(d.keys())[:15]:
        v = d[k]
        if isinstance(v, (str, int, float, bool)):
            print(f'  {k}: {v}')
        elif isinstance(v, list):
            print(f'  {k}: [{len(v)} items]')
        elif isinstance(v, dict):
            print(f'  {k}: {json.dumps(v)[:120]}')
" 2>/dev/null

echo ""
echo "=== AI BRAIN TOOLS ==="
curl -s "$BASE/api/ivx/ai-brain/tools" -H "Authorization: Bearer $TOKEN" 2>/dev/null | python3 -c "
import sys, json
d = json.load(sys.stdin)
if isinstance(d, dict):
    tools = d.get('tools', d.get('data', []))
    if isinstance(tools, list):
        print(f'Total AI Brain tools: {len(tools)}')
        for t in tools[:15]:
            if isinstance(t, dict):
                print(f'  - {t.get(\"name\",\"?\")}: {t.get(\"purpose\",\"?\")[:60]}')
            else:
                print(f'  - {t}')
    else:
        for k in sorted(d.keys())[:10]:
            print(f'  {k}: {str(d[k])[:100]}')
" 2>/dev/null

